let state={},managed={},artifacts=[],capmap={capabilities:[]},versions={applications:[]},cicd={environments:[]},tab='control',selected=0,appScope='ALL',promotionAction='promote-dev-test',devContext='ADMIN_WEB',workflowMode='Workflow Chat';
const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const text=x=>Object.values(x||{}).join(' ').toLowerCase();
const norm=s=>String(s||'').toLowerCase().replace(/[^a-z0-9]+/g,' ').trim();
function bucket(t){t=String(t||'').toLowerCase();if(/stuck|blocked|fail|rejected|not approved|not implemented|missing|rollback|no go|stop/.test(t))return 'stuck';if(/pending|review|planned|deferred|in progress|candidate|not active|partial|warning/.test(t))return 'open';if(/pass|solved|closed|complete|verified|validated|confirmed|active|canonical|baseline|ready/.test(t))return 'done';return 'other'}
function chip(b,l){const i={done:'✅',open:'⚠️',stuck:'⛔',other:'ℹ️'}[b]||'ℹ️';const t=l||{done:'PASS / Done',open:'Warning / Review',stuck:'Blocked / Stop',other:'Info / N/A'}[b]||'Info / N/A';return `<span class='chip ${b}'>${i} ${esc(t)}</span>`}
function capBucket(c){const r=parseInt(String(c.readiness||'0').replace('%',''),10)||0;return r>=75?'done':r>=40?'open':'stuck'}
function work(){return managed.register_rows||[]}
function classify(r){return bucket(`${r.lifecycle} ${r.state}`)}
function parseArtifacts(md){return md.split('\n').filter(l=>l.startsWith('| ')&&!l.includes('---')&&!l.includes('Artifact ID')).map(l=>{const p=l.split('|').slice(1,-1).map(x=>x.trim().replaceAll('`',''));return {id:p[0],name:p[1],location:p[2],status:p[3],domain:p[4],initiative:p[5]}}).filter(x=>x.id)}
