const match=(items,terms)=>(items||[]).filter(x=>(terms||[]).some(t=>text(x).includes(String(t).toLowerCase())));
function findings(){return [...(managed.not_full_backlog_warning||[]).map((r,i)=>({id:`FIND-WARN-${i+1}`,title:r.warning,category:'Finding / Warning',lifecycle:'Finding',state:r.dashboard_effect||'',source:r.repo_basis||'managed-work.json'})),...(managed.why_task_count_looked_small||[]).map((r,i)=>({id:`FIND-CAUSE-${i+1}`,title:r.reason,category:'Finding / Cause',lifecycle:'Finding',state:r.meaning||'',source:'managed-work.json'})),...(managed.next_dashboard_improvements||[]).map(r=>({id:r.id,title:r.label,category:'Finding / Improvement Candidate',lifecycle:'Future Improvement',state:r.status,source:'managed-work.json'}))]}
function appOfName(name,layer=''){const s=(name+' '+layer).toLowerCase();if(/pool|chemical|measurement|alert|maintenance/.test(s))return 'RANI_POOL';if(/trading|trade|broker|market|visual context|decision|execution engine|data ingestion|system logs|research|model evolution/.test(s))return 'RANI_TRADING';return 'RANI_OS'}
function appOfCap(c){return c.application||appOfName(c.name||c.capability,c.layer)}
function appOfWork(r){const s=text(r);if(/pool|chemical|measurement|maintenance/.test(s))return 'RANI_POOL';if(/trading|trade|broker|market|ibkr|verdict|execution|evidence/.test(s))return 'RANI_TRADING';return 'RANI_OS'}
function appOfArtifact(a){const s=text(a);if(/pool|chemical|maintenance/.test(s))return 'RANI_POOL';if(/trading|trade|broker|market|visual|pine|gpt_decision|gpt_brain|execution/.test(s))return 'RANI_TRADING';return 'RANI_OS'}
function inScope(a){return appScope==='ALL'||a===appScope}
function capabilityUniverse(){const roadmap=(state.capabilities||[]).map(c=>({name:c.capability,source:'Capability Roadmap',readiness:c.readiness,status:c.status,layer:c.layer,priority:c.priority,next:c.next}));const mapped=(capmap.capabilities||[]).map(c=>({name:c.name,source:'Explicit Capability Map',readiness:c.readiness,status:c.status,layer:c.layer,priority:c.priority,next:c.next_safe_action,capability_id:c.capability_id,application:appOfCap(c)}));const pool=[{name:'POOL_CONTROLLER Framework',source:'Application Boundary',readiness:'0%',status:'Framework / Not Implemented',layer:'Application / Pool',priority:'P3',next:'Do not implement until owner approves',capability_id:'CAP-POOL-FRAMEWORK',application:'RANI_POOL'}];const m=new Map();[...roadmap,...mapped,...pool].forEach(c=>{const k=norm(c.name);m.set(k,{...(m.get(k)||{}),...c,application:c.application||appOfName(c.name,c.layer)})});return [...m.values()]}
function model(){return (capmap.capabilities||[]).map((c,i)=>{const known=(c.known_work_ids||[]).map(id=>byId(work(),id)).filter(Boolean);const blockers=(c.blocking_bug_ids||[]).map(id=>byId(work(),id)).filter(Boolean);const cand=(c.candidate_ids||[]).map(id=>byId(work(),id)).filter(Boolean);const arts=match(artifacts,c.artifact_queries||[]);const finds=match(findings(),c.finding_queries||[]);const app=appOfCap(c);const gates=c.owner_gates||[];return {i,c:{...c,application:app},known,blockers,cand,arts,finds,missing:c.missing_work||[],check:c.completion_checklist||[],gates}}).filter(x=>inScope(x.c.application))}
function table(rows,cols){return `<div class='note table-count'>Records in this table: ${(rows||[]).length}</div><div class='tablewrap'><table><thead><tr>${cols.map(c=>`<th>${esc(c[0])}</th>`).join('')}</tr></thead><tbody>${(rows||[]).map(r=>`<tr>${cols.map(c=>`<td>${r[c[1]]??''}</td>`).join('')}</tr>`).join('')||`<tr><td colspan='${cols.length}' class='bad'>No matching rows</td></tr>`}</tbody></table></div>`}
function mobileCards(rows,fields,label){return `<div class='mobile-cardwrap' aria-label='${esc(label)} mobile cards'>${(rows||[]).map(r=>`<article class='mobile-card'>${fields.map(([name,key])=>`<div class='mobile-field'><div class='mobile-label'>${esc(name)}</div><div class='mobile-value'>${r[key]??''}</div></div>`).join('')}</article>`).join('')||`<div class='mobile-card bad'>No matching rows</div>`}</div>`}
