function envBuild(name){return name===env.environment?env.build:name==='PROD'?'Stable production build':name==='PRE-PROD'?'Release candidate build':name==='TEST'?'Validation build':'Experimental build'}
function promotionMatrixRows(){return ['DEV','TEST','PRE-PROD','PROD'].map(name=>{const profile=envProfiles[name]||{};const next={DEV:'TEST',TEST:'PRE-PROD','PRE-PROD':'PROD',PROD:'None — top environment'}[name];const status={DEV:'Source for explicit promotion only',TEST:'Holds validation build until promoted','PRE-PROD':'Holds release candidate behind Owner Gate',PROD:'Stable until owner-approved promotion'}[name];return {Environment:esc(name),Build:esc(envBuild(name)),Mode:esc(name===env.environment?env.capability_mode:(name==='PROD'?'stable':name==='DEV'?'experimental':'validation')),Gate:name==='DEV'?esc('No for DEV changes; yes when entering gated environments'):esc(name==='PROD'?'Owner Gate required':'Review gate required'),Status:esc(status),Rollback:esc(profile.rollback_target||'none'),Next:esc(next)}})}
function promotionActions(){return [['promote-dev-test','Promote DEV → TEST','Prepare handoff to update only env/test/index.html'],['promote-test-preprod','Promote TEST → PRE-PROD','Prepare handoff to update only env/preprod/index.html'],['promote-preprod-prod','Promote PRE-PROD → PROD','Prepare owner-gated handoff to update only index.html'],['rollback-test','Rollback TEST','Prepare TEST rollback handoff only'],['rollback-preprod','Rollback PRE-PROD','Prepare PRE-PROD rollback handoff only'],['rollback-prod','Rollback PROD','Prepare owner-confirmed PROD rollback handoff only']].map(([id,label,meta])=>`<button class='launcher-card ${promotionAction===id?'active':''}' data-promotion='${id}'><strong>${esc(label)}</strong><span class='launcher-meta'>${esc(meta)}</span></button>`).join('')}
function promotionMatrix(){const fields=[['Environment','Environment'],['Current Build','Build'],['Capability Mode','Mode'],['Owner Gate Required','Gate'],['Promotion Status','Status'],['Rollback Target','Rollback'],['Next Allowed Promotion','Next']];return `<section><h2>Promotion Matrix</h2><div class='boundary-note'>Different environments may intentionally run different builds. This is expected. A build moves upward only through explicit promotion.</div><div class='note'>ADMIN-PROMOTION-FLOW-001 — Environment Promotion Workflow Standard.</div>${responsiveRecords(promotionMatrixRows(),fields,fields,'Promotion Matrix')}<div class='review-warning'>Promotion is a governed Git change. This MVP prepares the handoff prompt and checklist; it does not bypass GitHub, Codex, PR review, Owner Gate, or Source of Truth.</div><div class='boundary-note'>This workflow is compatible with future full environment separation. In the future, the same DEV → TEST → PRE-PROD → PROD workflow can trigger deployment pipelines instead of editing static entrypoint files.</div><h3>Governed Promotion Actions</h3><div class='launcher-grid promotion-actions'>${promotionActions()}</div><h3>Selected Handoff Prompt / Checklist</h3><div class='note'>Copy this prompt into Codex. These actions do not directly change files.</div><pre class='prompt-block'>${esc(promotionPrompts[promotionAction]||promotionPrompts['promote-dev-test'])}</pre></section>`}

function cicdView(){const rows=(cicd.environments||[]).map(e=>({Environment:esc(titleCase(e.name)),Status:esc(e.status),Health:health(e.health),Purpose:esc(e.purpose),Promotion:esc(e.promotion_rule),Rollback:esc(e.rollback_rule),Gap:esc(cicd.current_gap),Next:esc(cicd.next_safe_action)}));const tableFields=[['Development / Testing / Pre-Prod / Production','Environment'],['Status','Status'],['Health','Health'],['Purpose','Purpose'],['Promotion rules','Promotion'],['Rollback rules','Rollback'],['Current gap','Gap'],['Next safe action','Next']];return `<section><h2>CI/CD View</h2><div class='note'>Pipeline: ${esc(cicd.required_pipeline||'Build -> Dev -> Test -> Pre-Prod -> Owner PASS -> Production')}. Mobile uses readable cards with advanced rules collapsed by default.</div>${cicdRecords(rows,tableFields)}</section>`}

function workflowContextData(){return {
RANI_OS:{step:'Update Source of Truth',open:'Existing Chat',copy:'CURRENT_STATE prompt',paste:'Workflow Chat',ret:'Development Tools',target:'RANI_OS project chat'},
ADMIN_WEB:{step:'Run Codex implementation',open:'Codex Cloud',copy:'Codex prompt',paste:'Codex task input',ret:'GitHub PR review',target:'Admin app change'},
RANI_TRADING:{step:'Review trading evidence',open:'Existing Chat',copy:'Evidence prompt',paste:'Workflow Chat',ret:'PASS / FAIL note',target:'Trading review'},
RANI_POOL:{step:'Review pool safety',open:'Existing Chat',copy:'Safety prompt',paste:'Workflow Chat',ret:'Owner decision',target:'Pool review'}}}
function currentWorkflowContext(){return workflowContextData()[devContext]||workflowContextData().ADMIN_WEB}
function adminEnvUrl(){const base='https://rani12k.github.io/rani-os-admin-preview/';const path=env.environment==='DEV'?'env/dev/':env.environment==='TEST'?'env/test/':env.environment==='PRE-PROD'?'env/preprod/':'';return `${base}${path}?v=devtools002`}
function currentActionRows(ctx){return [['Active Context',devContext],['Mode',workflowMode],['Step',ctx.step],['Open',ctx.open],['Copy',ctx.copy],['Paste',ctx.paste],['Return',ctx.ret]]}
function compactDetails(title,body){return `<details class='tool-details compact-details'><summary>${esc(title)}</summary>${body}</details>`}
function developmentTools(){const ctx=currentWorkflowContext();const contexts=Object.keys(workflowContextData());const handoff=`Copy this: ${ctx.copy}\nPaste here: ${ctx.paste}\nExpected result: ${ctx.target}\nReturn to: ${ctx.ret}`;const primary=[['Open Existing Chat','https://chatgpt.com/','Chat: “May open ChatGPT home. Return manually to the existing RANI_OS project chat.”'],['Open Codex','https://chatgpt.com/codex','Codex: “Paste the prompt there.”'],['Open GitHub PRs','https://github.com/rani12k/rani-os-admin-preview/pulls','GitHub PRs: “Review changed files and merge.”'],['Open Target Admin Env',adminEnvUrl(),'Admin Env: “Open the environment for screenshot review.”']];const modeLine='Workflow Chat = part of task. Free Chat = side question, no state change.';const fields=[['Environment','Environment'],['Current Build','Build'],['Capability Mode','Mode'],['Owner Gate Required','Gate'],['Promotion Status','Status'],['Rollback Target','Rollback'],['Next Allowed Promotion','Next']];const promotionBody=`<div class='boundary-note'>Different environments may intentionally run different builds.</div>${responsiveRecords(promotionMatrixRows(),fields,fields,'Promotion Matrix')}<h3>Promote / Rollback</h3><div class='launcher-grid promotion-actions'>${promotionActions()}</div><pre class='prompt-block'>${esc(promotionPrompts[promotionAction]||promotionPrompts['promote-dev-test'])}</pre>`;const checklist=['Codex completed','PR reviewed','PR merged','Admin env opened','screenshot reviewed','PASS / FAIL','Source of Truth updated'];const referenceBody=`<div class='boundary-note'>External tools are launched, not embedded.</div><div class='boundary-note'>Existing ChatGPT thread cannot be guaranteed.</div><div class='boundary-note'>CURRENT_STATE.md wins.</div><div class='boundary-note'>Branch protection risk remains open.</div>`;return `<section class='action-card current-action-card'><h2>CURRENT ACTION</h2><div class='action-grid compact-action-grid'>${currentActionRows(ctx).map(([k,v])=>`<div class='action-item'><strong>${esc(k)}</strong>${esc(v)}</div>`).join('')}</div></section><section class='primary-actions'><h2>Open Tools</h2><div class='launcher-grid'>${primary.map(([label,url,meta])=>`<div class='launcher-card'><a href='${esc(url)}' target='_blank' rel='noopener noreferrer'>${esc(label)}</a><div class='launcher-meta'>${esc(meta)}</div></div>`).join('')}</div></section><section><h2>Context</h2><div class='context-grid compact-selector'>${contexts.map(c=>`<button class='context-card ${devContext===c?'active':''}' data-dev-context='${esc(c)}'><strong>${esc(c)}</strong></button>`).join('')}</div></section><section><h2>Mode</h2><div class='note'>${esc(modeLine)}</div><div class='mode-grid compact-selector'>${['Workflow Chat','Free Chat'].map(m=>`<button class='mode-card ${workflowMode===m?'active':''}' data-workflow-mode='${esc(m)}'><strong>${esc(m)}</strong></button>`).join('')}</div></section><section><h2>Copy / Paste</h2><pre class='prompt-block compact-prompt'>${esc(handoff)}</pre></section>${compactDetails('Promotion Flow — DEV → TEST → PRE-PROD → PROD',promotionBody)}${compactDetails('Review Checklist',`<div class='checklist-grid'>${checklist.map(x=>`<div class='checklist-item'>${esc(x)}</div>`).join('')}</div>`)}${compactDetails('Reference Notes',referenceBody)}<section><h2>Branch Protection</h2><div class='review-warning'>BRANCH-PROTECTION-001 — OPEN RISK — main branch is not protected yet; keep manual PR review.</div></section>`}
function workflowHub(){return developmentTools()}


function configCenter(){const flags=env.feature_flags&&typeof env.feature_flags==='object'?Object.entries(env.feature_flags).map(([k,v])=>`${esc(k)}: ${esc(v)}`).join('<br>'):'None';const rows=[['app',env.app],['environment',env.environment],['build',env.build],['capability_mode',env.capability_mode],['data_scope',env.data_scope],['owner_gate_required',boolLabel(env.owner_gate_required)],['writes_allowed',boolLabel(env.writes_allowed)],['debug_tools_allowed',boolLabel(env.debug_tools_allowed)],['experimental_ui_allowed',boolLabel(env.experimental_ui_allowed)],['rollback_target',env.rollback_target],['banner',env.banner],['theme',env.theme],['risk_level',env.risk_level],['risk_mode',riskMode()],['risk_color',riskColor()||'none'],['config_version',env.config_version],['role_profile',env.role_profile],['feature_flags',flags]];return `<section><h2>Config Center</h2><div class='config-rule'>Config selects and constrains existing capabilities. New UI or logic requires a new build.</div>${env.environment==='PROD'?`<div class='prod-note'>Production admin is restricted by default. Debug, experimental, migration, and destructive controls are disabled unless explicitly owner-approved.</div>`:''}${table(rows.map(([K,V])=>({K:esc(K),V:K==='feature_flags'?flags:esc(V)})),[['Config Field','K'],['Active Value','V']])}</section>`}
function roleAccess(){const rows=[{Role:'System Admin',View:'Environment status, config metadata, CI/CD, capability maps, work records, artifacts, version state, owner gate status.',Manage:'Non-production admin workflows only when the active config allows writes or tools.',NoBypass:'System Admin does not automatically bypass Owner Gate; cannot override production restrictions, destructive controls, migrations, or owner approval.'},{Role:'User / Operator',View:'Published dashboard status, readable reports, scoped records, non-sensitive environment indicators.',Manage:'Routine review/navigation only; no production writes in the current admin preview.',NoBypass:'May not bypass Owner Gate, environment isolation, capability constraints, rollback policy, or disabled debug/experimental controls.'},{Role:'Owner Gate',View:'Owner-visible candidate, production, rollback, and gated action context.',Manage:'Explicit approval or rejection of gated promotions/actions and production exceptions.',NoBypass:'Must still follow build pinning, environment isolation, auditability, and rollback constraints.'}];return `<section><h2>Role / Access</h2><div class='note'>Access is separated from environment configuration. System Admin does not automatically bypass Owner Gate.</div>${table(rows.map(r=>({Role:esc(r.Role),View:esc(r.View),Manage:esc(r.Manage),NoBypass:esc(r.NoBypass)})),[['Role','Role'],['May View','View'],['May Manage','Manage'],['May Not Bypass','NoBypass']])}</section>`}

function priority(){return `<section><h2>Priority Board</h2>${capTable(model())}</section>`}
function capmapView(){return `<section><h2>Capability Map</h2>${capTable(model())}</section>`}
function unmapped(){const keys=new Set((capmap.capabilities||[]).map(c=>norm(c.name)));const rows=capabilityUniverse().filter(c=>!keys.has(norm(c.name))&&inScope(c.application)).map(c=>({c:{...c,mapping_confidence:'Unmapped',next_safe_action:'Create capability-map entry'},known:[],blockers:[],cand:[],arts:[],finds:[],missing:['Create capability_id'],check:[],gates:[]}));return `<section><h2>Unmapped Capabilities</h2>${capTable(rows)}</section>`}
function owner(){let rows=[];model().forEach(x=>x.gates.forEach(g=>rows.push({App:esc(x.c.application),Cap:esc(x.c.name),Gate:esc(g),Status:chip('open','Owner Gate'),Next:esc(x.c.next_safe_action)})));return `<section><h2>Owner Gates</h2>${table(rows,[['App','App'],['Capability','Cap'],['Gate','Gate'],['Status','Status'],['Next','Next']])}</section>`}
function workView(){return `<section><h2>Work Records</h2>${workTable(work())}</section>`}
function artView(){return `<section><h2>Artifacts</h2>${artifactTable(artifacts)}</section>`}
function reports(){return `<section><h2>Reports</h2>${capTable(model())}</section>`}
function view(){return tab==='workflow'?workflowHub():tab==='mapping'?mapping():tab==='priority'?priority():tab==='capmap'?capmapView():tab==='unmapped'?unmapped():tab==='owner'?owner():tab==='work'?workView():tab==='artifacts'?artView():tab==='versions'?versionCenter():tab==='config'?configCenter():tab==='roles'?roleAccess():tab==='cicd'?cicdView():tab==='reports'?reports():control()}
function render(){layout(view())}
function wire(){document.querySelectorAll('[data-app]').forEach(b=>b.onclick=()=>{appScope=b.dataset.app;render()});document.querySelectorAll('[data-tab]').forEach(b=>{b.classList.toggle('active',b.dataset.tab===tab);b.onclick=()=>{tab=b.dataset.tab;render()}});document.querySelectorAll('[data-nav]').forEach(b=>b.onclick=()=>{tab=b.dataset.nav==='work'?'work':b.dataset.nav==='artifacts'?'artifacts':b.dataset.nav==='owner'?'owner':b.dataset.nav==='unmapped'?'unmapped':'control';render()});document.querySelectorAll('[data-promotion]').forEach(b=>b.onclick=()=>{promotionAction=b.dataset.promotion;render()});document.querySelectorAll('[data-dev-context]').forEach(b=>b.onclick=()=>{devContext=b.dataset.devContext;render()});document.querySelectorAll('[data-workflow-mode]').forEach(b=>b.onclick=()=>{workflowMode=b.dataset.workflowMode;render()})}
async function boot(){css();const [st,mw,md,cm,vc,cd]=await Promise.all([fetch(new URL('state.json?b=cr016-'+stamp,assetBase),{cache:'no-store'}).then(r=>r.json()),fetch(new URL('managed-work.json?b=cr016-'+stamp,assetBase),{cache:'no-store'}).then(r=>r.json()),fetch(new URL('artifact-register-public.md?b=cr016-'+stamp,assetBase),{cache:'no-store'}).then(r=>r.text()),fetch(new URL('capability-map.json?b=cr016-'+stamp,assetBase),{cache:'no-store'}).then(r=>r.json()),fetch(new URL('version-center.json?b=cr016-'+stamp,assetBase),{cache:'no-store'}).then(r=>r.json()),fetch(new URL('cicd-environments.json?b=cr016-'+stamp,assetBase),{cache:'no-store'}).then(r=>r.json())]);state=st;managed=mw;artifacts=parseArtifacts(md);capmap=cm;versions=vc;cicd=cd;render()}
boot().catch(()=>{document.body.innerHTML='<section><div class="bad">Could not load safe dashboard data</div></section>'});
